import{_ as d,c as n,a as e,b as r,d as i,r as s,o as l}from"./app-DxT-J_20.js";const o={};function h(p,t){const a=s("DateMeta");return l(),n("div",null,[t[0]||(t[0]=e("h1",{id:"클렌징-밀크-cleansing-milk",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#클렌징-밀크-cleansing-milk"},[e("span",null,"클렌징 밀크 (Cleansing Milk)")])],-1)),r(a),t[1]||(t[1]=i(`<h2 id="왜-밀크-인가" tabindex="-1"><a class="header-anchor" href="#왜-밀크-인가"><span>왜 &quot;밀크&quot;인가</span></a></h2><p>클렌징 밀크(Cleansing Milk)는 외관과 질감이 우유(milk)를 닮은 유백색의 에멀전(emulsion) 형태 클렌저다. 기름과 물이 계면활성제에 의해 균일하게 혼합된 상태로, 실제 우유의 지방과 물이 에멀전을 이루는 것과 같은 원리다. 색상, 농도, 부드러운 질감 모두 우유와 유사해 이 이름이 붙었다.</p><h3 id="에멀전이란" tabindex="-1"><a class="header-anchor" href="#에멀전이란"><span>에멀전이란</span></a></h3><p>에멀전은 두 가지 서로 섞이지 않는 액체(주로 기름과 물) 중 하나가 다른 하나에 미세한 방울 형태로 분산된 상태다. 클렌징 밀크는 <strong>수중유(O/W, Oil in Water)</strong> 에멀전으로, 소량의 오일이 물 속에 분산되어 있다.</p><ul><li>클렌징 오일: 거의 100% 오일 베이스</li><li>클렌징 밀크: 오일이 물에 분산 → 부드럽고 가벼운 질감</li><li>클렌징 폼: 계면활성제 + 물 위주, 거품 생성</li></ul><hr><h2 id="클렌징-밀크의-세정-원리" tabindex="-1"><a class="header-anchor" href="#클렌징-밀크의-세정-원리"><span>클렌징 밀크의 세정 원리</span></a></h2><p>클렌징 밀크에 포함된 오일 성분이 피지, 선크림, 가벼운 메이크업 등의 유성 오염물과 <strong>&quot;유사한 것은 유사한 것을 녹인다(like dissolves like)&quot;</strong> 원리로 결합한다. 동시에 물 베이스의 연속상(continuous phase)이 피부에서 쉽게 씻겨 나가도록 돕는다.</p><p>세정력 순서 (일반적으로):</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">클렌징 오일 &gt; 클렌징 밤 &gt; 클렌징 밀크 &gt; 클렌징 폼 &gt; 클렌징 워터</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>방수 마스카라, 워터프루프 파운데이션 등의 <strong>내수성 화장품은 클렌징 밀크만으로 완전 제거가 어려울 수 있다</strong>. 이 경우 더블 클렌징(클렌징 오일 → 클렌징 폼)이 권장된다.</p><hr><h2 id="어떤-피부에-적합한가" tabindex="-1"><a class="header-anchor" href="#어떤-피부에-적합한가"><span>어떤 피부에 적합한가</span></a></h2><p>클렌징 밀크는 <strong>건성, 극건성, 민감성</strong> 피부에 특히 잘 맞는다.</p><table><thead><tr><th>피부 타입</th><th>클렌징 밀크 적합도</th></tr></thead><tbody><tr><td>건성</td><td>★★★★★ (세정 후 당김이 적음)</td></tr><tr><td>민감성</td><td>★★★★★ (계면활성제 자극이 낮음)</td></tr><tr><td>복합성</td><td>★★★★ (T존 피지 제거는 추가 클렌징 필요할 수 있음)</td></tr><tr><td>지성</td><td>★★★ (잔여감이 남을 수 있음)</td></tr><tr><td>여드름성</td><td>★★★ (포뮬라에 따라 다름, 코메도제닉 성분 확인 필요)</td></tr></tbody></table><p>특히 피부 장벽이 약하거나 아토피성 피부에서, 거품 클렌저의 강한 계면활성제(라우릴황산나트륨 등)가 자극이 되는 경우 클렌징 밀크로 대체하면 세정 후 건조함이 크게 줄어드는 경우가 많다.</p><hr><h2 id="사용-방법" tabindex="-1"><a class="header-anchor" href="#사용-방법"><span>사용 방법</span></a></h2><h3 id="기본-사용법" tabindex="-1"><a class="header-anchor" href="#기본-사용법"><span>기본 사용법</span></a></h3><ol><li><strong>건조한 얼굴</strong>에 적당량(500원 동전 크기)을 덜어낸다</li><li>얼굴 전체에 부드럽게 마사지하듯 펴 바른다 (약 30~60초)</li><li>물을 약간 묻혀 유화(emulsification)시킨다 (하얗게 변하면서 느낌이 바뀜)</li><li>미온수로 깨끗이 씻어낸다</li></ol><div class="hint-container tip"><p class="hint-container-title">유화의 중요성</p><p>3번 단계에서 소량의 물을 먼저 추가해 유화시키는 것이 중요하다. 바로 물로 씻으면 오일이 피부에 남을 수 있고, 먼저 유화시키면 오염물과 오일이 함께 깔끔하게 씻겨 내려간다.</p></div><h3 id="더블-클렌징-시" tabindex="-1"><a class="header-anchor" href="#더블-클렌징-시"><span>더블 클렌징 시</span></a></h3><p>워터프루프 제품이나 자외선 차단제를 사용했다면:</p><ol><li>(1차) 클렌징 오일 또는 클렌징 밤으로 메이크업·선크림 제거</li><li>(2차) 클렌징 밀크로 마무리 세정</li></ol><p>이 경우 클렌징 밀크는 잔여 오일기를 정리하는 마지막 단계에서 부드럽게 마무리하는 역할을 한다.</p><h3 id="티슈오프-방법-선택" tabindex="-1"><a class="header-anchor" href="#티슈오프-방법-선택"><span>티슈오프 방법 (선택)</span></a></h3><p>물로 씻기 어려운 상황에서, 클렌징 밀크를 바른 후 화장솜이나 티슈로 닦아내는 방식도 가능하다. 단, 이 방법은 완전한 세정보다 피부 자극이 있을 수 있어 일상적 사용보다는 비상용으로 적합하다.</p><hr><h2 id="클렌징-밀크-vs-다른-클렌저-비교" tabindex="-1"><a class="header-anchor" href="#클렌징-밀크-vs-다른-클렌저-비교"><span>클렌징 밀크 vs 다른 클렌저 비교</span></a></h2><table><thead><tr><th>클렌저 유형</th><th>질감</th><th>세정력</th><th>보습감</th><th>적합 피부</th></tr></thead><tbody><tr><td>클렌징 오일</td><td>오일</td><td>★★★★★</td><td>★★★★</td><td>전 피부 (짙은 메이크업)</td></tr><tr><td>클렌징 밤</td><td>고체→오일</td><td>★★★★★</td><td>★★★★★</td><td>건성·민감성</td></tr><tr><td>클렌징 밀크</td><td>로션/크림</td><td>★★★★</td><td>★★★★</td><td>건성·민감성</td></tr><tr><td>클렌징 크림</td><td>크림</td><td>★★★★</td><td>★★★★★</td><td>극건성</td></tr><tr><td>클렌징 폼</td><td>거품</td><td>★★★</td><td>★★</td><td>지성·복합성</td></tr><tr><td>클렌징 워터 (미셀라)</td><td>물</td><td>★★</td><td>★★★</td><td>민감성 (라이트 클렌징)</td></tr></tbody></table><hr><h2 id="주요-성분-읽기" tabindex="-1"><a class="header-anchor" href="#주요-성분-읽기"><span>주요 성분 읽기</span></a></h2><p>클렌징 밀크 구매 시 확인할 성분:</p><p><strong>좋은 성분</strong></p><ul><li>세라마이드(Ceramide): 세정 중 장벽 성분 보충</li><li>판테놀(Panthenol): 진정, 수분 유지</li><li>글리세린(Glycerin): 보습</li></ul><p><strong>주의 성분</strong></p><ul><li>미네랄 오일(Mineral Oil): 코메도제닉 가능성, 여드름성 피부에 주의</li><li>SLS/SLES (소듐라우릴황산염): 거품 클렌저에서 자극이 되는 성분, 클렌징 밀크에는 적게 사용됨</li><li>향료(Fragrance/Parfum): 민감성 피부에서 자극 가능</li></ul><hr><h2 id="추천-제품" tabindex="-1"><a class="header-anchor" href="#추천-제품"><span>추천 제품</span></a></h2><table><thead><tr><th>제품</th><th>특징</th><th>가격대</th></tr></thead><tbody><tr><td>닥터지 브라이트닝 필링 젤</td><td>—</td><td>—</td></tr><tr><td><strong>에스트라 아토베리어365 클렌저</strong></td><td>세라마이드, 극저자극, 아토피 피부용</td><td>2만원대</td></tr><tr><td><strong>세타필 젠틀 스킨 클렌저</strong></td><td>무향, 피부과 추천, 세계적 베스트셀러</td><td>1~2만원대</td></tr><tr><td><strong>라로슈포제 에파클라 겔</strong></td><td>지성 피부용이지만 저자극</td><td>2만원대</td></tr><tr><td><strong>웰라쥬 리얼 히알루로닉 클렌징 밀크</strong></td><td>히알루론산 보습, 국내 브랜드</td><td>1만원대</td></tr><tr><td><strong>파울러 빌베리 클렌징 밀크</strong></td><td>식물성 원료, 건성·민감성 특화</td><td>3만원대</td></tr></tbody></table><hr><div class="hint-container info"><p class="hint-container-title">클렌징 밀크와 클렌징 로션의 차이</p><p>클렌징 밀크와 클렌징 로션은 본질적으로 같은 포뮬라 타입이다. 로션은 밀크보다 약간 점도가 높은 경향이 있지만, 브랜드마다 명칭을 혼용하는 경우가 많아 실질적 차이보다는 마케팅적 명칭 차이로 보는 것이 적절하다.</p></div>`,42))])}const m=d(o,[["render",h]]),g=JSON.parse('{"path":"/products/cleansing-milk.html","title":"클렌징 밀크 (Cleansing Milk)","lang":"ko-KR","frontmatter":{"description":"클렌징 밀크 (Cleansing Milk)","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"클렌징 밀크 (Cleansing Milk)\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-12T15:12:24.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/products/cleansing-milk.html"}],["meta",{"property":"og:title","content":"클렌징 밀크 (Cleansing Milk)"}],["meta",{"property":"og:description","content":"클렌징 밀크 (Cleansing Milk)"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T15:12:24.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T15:12:24.000Z"}]]},"git":{"createdTime":1781277144000,"updatedTime":1781277144000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":1,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"867901d169b73496a8a67d2853b6d0b27bdbf876","time":1781277144000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: rename all files to lowercase and add Products/Finance articles","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]}]},"filePathRelative":"products/cleansing-milk.md","autoDesc":true}');export{m as comp,g as data};
